def mean_from_csv(path):
    """从 CSV 文件第一列读取数字并返回平均值。"""
    numbers = []

    with open(path, 'r') as f:
        for line in f:
            line = line.strip()
            if not line:  # 跳过空行
                continue

            # 获取第一列值
            parts = line.split(',')
            if not parts:
                continue

            value = parts[0].strip()

            try:
                num = float(value)
                numbers.append(num)
            except ValueError:
                continue  # 跳过非数字值

    if not numbers:
        return None

    return sum(numbers) / len(numbers)

import csv

def mean_from_csv(path):
    """Read first column of CSV file and return mean of numeric values."""
    numbers = []

    with open(path, 'r', newline='') as f:
        reader = csv.reader(f)
        for row in reader:
            if not row:  # Skip empty rows
                continue
            try:
                value = float(row[0])  # First column
                numbers.append(value)
            except (ValueError, IndexError):
                continue  # Skip non-numeric values

    if not numbers:
        return 0.0  # Return 0 if no valid numbers found

    return sum(numbers) / len(numbers)
